import os
from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import FAISS
from langchain.llms import OpenAI
from langchain.chains import RetrievalQA
from langchain.document_loaders import TextLoader

# Step 1: Load company documents into vector database
def load_documents(directory):
    documents = []
    for filename in os.listdir(directory):
        if filename.endswith('.txt'):
            loader = TextLoader(os.path.join(directory, filename))
            documents.extend(loader.load())
    return documents

def create_vector_store(documents):
    embeddings = OpenAIEmbeddings()
    vector_store = FAISS.from_documents(documents, embeddings)
    return vector_store

# Step 2: Set up the RAG system
def setup_rag_system(vector_store):
    llm = OpenAI()
    retrieval_qa = RetrievalQA(llm=llm, retriever=vector_store.as_retriever())
    return retrieval_qa

# Step 3: User query handling
def handle_query(retrieval_qa, query):
    response = retrieval_qa.run(query)
    return response

# Load documents and create vector store
documents = load_documents('company_documents')
vector_store = create_vector_store(documents)

# Set up RAG system
rag_system = setup_rag_system(vector_store)

# Example of handling a user query
user_query = "What is our company's policy on remote work?"
response = handle_query(rag_system, user_query)
print(response)

